#!/usr/bin/env bash\nset -euo pipefail\n\n# РЈСЃС‚Р°РЅРѕРІРєР° РѕС„РёС†РёР°Р»СЊРЅРѕРіРѕ OpenAI CLI (С‚СЂРµР±СѓРµС‚ OPENAI_API_KEY Сѓ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ).\n\nif [[ $EUID -ne 0 ]]; then\n  echo "РџРѕР¶Р°Р»СѓР№СЃС‚Р°, Р·Р°РїСѓСЃС‚РёС‚Рµ СЌС‚РѕС‚ СЃРєСЂРёРїС‚ СЃ sudo РёР»Рё РѕС‚ root (РґР»СЏ СЃРёСЃС‚РµРјРЅС‹С… РїР°РєРµС‚РѕРІ)."\n  exit 1\nfi\n\necho "[install-openai-cli] РЈСЃС‚Р°РЅРѕРІРєР° Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№..."\napt-get update -y\nDEBIAN_FRONTEND=noninteractive apt-get install -y python3 python3-pip ca-certificates\n\necho "[install-openai-cli] РЈСЃС‚Р°РЅРѕРІРєР° РїР°РєРµС‚Р° openai..."\npython3 -m pip install --upgrade pip setuptools wheel\npython3 -m pip install --upgrade openai\n\ncat <<'EOF'\n[install-openai-cli] Р“РѕС‚РѕРІРѕ.\n\nР”Р»СЏ СЂР°Р±РѕС‚С‹ CLI РЅРµРѕР±С…РѕРґРёРјРѕ:\n  1. РџРѕР»СѓС‡РёС‚СЊ API-РєР»СЋС‡ OpenAI.\n  2. Р­РєСЃРїРѕСЂС‚РёСЂРѕРІР°С‚СЊ РїРµСЂРµРјРµРЅРЅСѓСЋ РѕРєСЂСѓР¶РµРЅРёСЏ:\n     export OPENAI_API_KEY="РІР°С€_РєР»СЋС‡"\n  3. РСЃРїРѕР»СЊР·РѕРІР°С‚СЊ РєРѕРјР°РЅРґС‹ РІРёРґР°:\n     openai chat.completions.create -m gpt-4.1 -g "help me with..."\nEOF\n\n